SELECT 
    COUNT(*) AS q4_sales_count,
    SUM(CASE WHEN sale_date LIKE '2023-10-%' OR sale_date LIKE '2023-11-%' OR sale_date LIKE '2023-12-%' THEN 1 ELSE 0 END) AS q4_sales_count_actual,
    SUM(CASE WHEN return_date LIKE '2023-10-%' OR return_date LIKE '2023-11-%' OR return_date LIKE '2023-12-%' THEN 1 ELSE 0 END) AS q4_returns_count_actual
FROM (
    SELECT 1 AS dummy UNION ALL SELECT 2 UNION ALL SELECT 3
) dummy_tbl
CROSS JOIN (
    SELECT COUNT(*) AS q4_sales_count FROM sales WHERE sale_date LIKE '2023-10-%' OR sale_date LIKE '2023-11-%' OR sale_date LIKE '2023-12-%'
) s,
(
    SELECT COUNT(*) AS q4_returns_count FROM returns WHERE return_date LIKE '2023-10-%' OR return_date LIKE '2023-11-%' OR return_date LIKE '2023-12-%'
) r;
